    sessions = pgTable("sessions", {
      id: varchar("id").primaryKey().default(sql2`gen_random_uuid()`),
      academyId: varchar("academy_id").references(() => academies.id),
      coachId: varchar("coach_id").references(() => coaches.id),
      courtId: varchar("court_id").references(() => courts.id),
      locationId: varchar("location_id").references(() => locations.id),
      startTime: timestamp("start_time").notNull(),
      endTime: timestamp("end_time").notNull(),
      duration: integer("duration").notNull(),
      // minutes
      sessionType: text("session_type").notNull(),
      // private/semi/group/physical/activity
      ballLevel: text("ball_level"),
      skillLevel: integer("skill_level"),
      title: text("title"),
      // Display name like "Sunset Rally", "Glow Doubles"
      maxPlayers: integer("max_players").default(6),
      // Max players for group sessions
      xpReward: integer("xp_reward").default(20),
      // XP earned for attending
      vibe: text("vibe").default("casual"),
      // casual/competitive
      minLevel: integer("min_level"),
      // Minimum player level
      maxLevel: integer("max_level"),
      // Maximum player level
      isRecurring: boolean("is_recurring").default(false),
      recurringGroupId: varchar("recurring_group_id"),
      seriesId: varchar("series_id"),
      // References coachingSeries.id - links session to its parent series
      weekNumber: integer("week_number"),
      // Which week in the series (1, 2, 3...)
      weekCount: integer("week_count"),
      // 1/5/10/15/20
      isModifiedFromSeries: boolean("is_modified_from_series").default(false),
      // edited individually
      isSkipped: boolean("is_skipped").default(false),
      // manually skipped
      skipReason: text("skip_reason"),
      // holiday/weather/other
      travelTime: integer("travel_time").default(0),
      // minutes
      paymentStatus: text("payment_status").default("unpaid"),
      // paid/unpaid/partial/package
      price: numeric("price"),
      // Layer 3: Price Snapshots - frozen at booking time
      academyPrice: numeric("academy_price"),
      // What player pays (snapshot from academyPricing)
      coachPayout: numeric("coach_payout"),
      // What coach earns (snapshot from coachContracts)
      academyMargin: numeric("academy_margin"),
      // academyPrice - coachPayout (calculated)
      pricingCurrency: text("pricing_currency").default("AED"),
      status: text("status").default("scheduled"),
      // scheduled/cancelled/completed
      // Cancellation tracking
      cancelledAt: timestamp("cancelled_at"),
      cancelledBy: varchar("cancelled_by"),
      // coach_id who marked the cancellation
      cancellationReason: text("cancellation_reason"),
      // Reason provided by coach for cancellation
      isLastMinuteCancellation: boolean("is_last_minute_cancellation").default(false),
      cancellationCharged: boolean("cancellation_charged").default(false),
      cancellationChargeAmount: numeric("cancellation_charge_amount"),
      googleCalendarEventId: text("google_calendar_event_id"),
      // External Google Calendar event ID for sync
      reminder1hSent: boolean("reminder_1h_sent").default(false),
      reminder30mSent: boolean("reminder_30m_sent").default(false),
      // Multi-sport support
      sport: text("sport").default("tennis"),
      // tennis | padel | pickleball
      createdAt: timestamp("created_at").defaultNow()
    });
