      // ==================== AUTO-RENEW ALERTS ====================
      async getAutoRenewAlerts(coachId) {
        const now2 = /* @__PURE__ */ new Date();
        const tenWeeksAgo = new Date(now2.getTime() - 10 * 7 * 24 * 60 * 60 * 1e3);
        const coachSessions = await db.select().from(sessions).where(and(
          eq(sessions.coachId, coachId),
          gte(sessions.startTime, tenWeeksAgo),
          lte(sessions.startTime, now2)
        )).orderBy(desc(sessions.startTime));
        const recurringGroups = /* @__PURE__ */ new Map();
        for (const session of coachSessions) {
          const startTime = new Date(session.startTime);
          const dayOfWeek = startTime.getUTCDay();
          const hour = startTime.getUTCHours();
          const minute = startTime.getUTCMinutes();
          const key = `${dayOfWeek}-${hour}:${minute}`;
          if (!recurringGroups.has(key)) {
            recurringGroups.set(key, []);
          }
          recurringGroups.get(key).push(session);
        }
        const alerts = [];
        for (const [, groupSessions] of recurringGroups) {
          if (groupSessions.length >= 8) {
            const weekNumber = groupSessions.length;
            if (weekNumber >= 9 && weekNumber <= 10) {
              const sessionPlayerRecords = await db.select().from(sessionPlayers).where(eq(sessionPlayers.sessionId, groupSessions[0].id));
              for (const sp of sessionPlayerRecords) {
                if (sp.playerId) {
                  const player2 = await db.select().from(players).where(eq(players.id, sp.playerId));
                  if (player2[0]) {
                    alerts.push({
                      playerId: sp.playerId,
                      playerName: player2[0].name,
                      weekNumber,
                      lastSessionDate: groupSessions[0].startTime.toISOString()
                    });
                  }
                }
              }
            }
          }
        }
        return alerts;
      },
