import { eq as eq9, and as and8 } from "drizzle-orm";
async function updatePillarProgress(playerId, sessionId, feedback) {
  const pillars = ["TECHNIQUE", "TACTICAL", "PHYSICAL", "MENTAL", "SOCIAL", "MATCH"];
  const sessionScore = (feedback.effort + feedback.execution + feedback.understanding) / 3;
  for (const pillar of pillars) {
    const [current] = await db.select().from(playerPillarProgress).where(and8(
      eq9(playerPillarProgress.playerId, playerId),
      eq9(playerPillarProgress.pillar, pillar)
    ));
    const alpha = 0.3;
    const pillarScore = feedback.pillarRatings?.[pillar] ?? sessionScore;
    let newScore;
    let trend;
    let delta;
    if (current) {
      const oldScore = Number(current.currentScore);
      newScore = alpha * pillarScore + (1 - alpha) * oldScore;
      const diff = newScore - oldScore;
      if (diff > 0.1) {
        trend = "improving";
        delta = `+${diff.toFixed(2)}`;
      } else if (diff < -0.1) {
        trend = "declining";
        delta = diff.toFixed(2);
      } else {
        trend = "stable";
        delta = "0.00";
      }
      await db.update(playerPillarProgress).set({
        currentScore: newScore.toFixed(2),
        trend,
        lastSessionDelta: delta,
        lastSessionId: sessionId,
        lastUpdatedAt: /* @__PURE__ */ new Date(),
        updatedAt: /* @__PURE__ */ new Date()
      }).where(eq9(playerPillarProgress.id, current.id));
    } else {
      newScore = pillarScore;
      trend = "stable";
      delta = "0.00";
      await db.insert(playerPillarProgress).values({
        playerId,
        pillar,
        currentScore: newScore.toFixed(2),
        trend,
        lastSessionDelta: delta,
        lastSessionId: sessionId,
        lastUpdatedAt: /* @__PURE__ */ new Date()
      });
    }
  }
}

