router4.get("/api/glow/players/:playerId/readiness", authMiddlewareWithFreshData, requireAcademy, async (req2, res) => {
  try {
    const { playerId } = req2.params;
    const academyId = req2.user.academyId;
    if (!await validatePlayerAccess(playerId, academyId)) {
      return res.status(404).json({ error: "Player not found" });
    }
    const [playerLevel] = await db.select({
      playerLevel: playerBallLevels,
      level: ballLevels
    }).from(playerBallLevels).innerJoin(ballLevels, eq13(playerBallLevels.levelId, ballLevels.id)).where(and12(
      eq13(playerBallLevels.playerId, playerId),
      eq13(playerBallLevels.status, "active")
    )).orderBy(desc9(playerBallLevels.assignedAt)).limit(1);
    if (!playerLevel) {
      return res.json({ ready: false, reason: "No level assigned", requirements: null });
    }
    const level = playerLevel.level;
    const requirements = level.promotionRequirements;
    if (!requirements || !level.promotionToLevelId) {
      return res.json({ ready: false, reason: "No promotion path available", requirements: null });
    }
    const levelSkillsData = await db.select().from(levelSkills).where(eq13(levelSkills.levelId, level.id));
    const skillIds = levelSkillsData.map((s) => s.skillId);
    const playerScores = await db.select().from(playerSkillScores2).where(and12(
      eq13(playerSkillScores2.playerId, playerId),
      inArray6(playerSkillScores2.skillId, skillIds)
    )).orderBy(desc9(playerSkillScores2.createdAt));
    const achievedSkills = [];
    const latestScoreBySkill = {};
    for (const score of playerScores) {
      if (!latestScoreBySkill[score.skillId]) {
        latestScoreBySkill[score.skillId] = score.score;
      }
    }
    for (const ls of levelSkillsData) {
      const playerScore = latestScoreBySkill[ls.skillId];
      if (playerScore !== void 0 && playerScore >= ls.targetScore) {
        achievedSkills.push(ls.skillId);
      }
    }
    const pillarProgress = await db.select().from(playerPillarProgress).where(eq13(playerPillarProgress.playerId, playerId));
    const pillarScores = {};
    for (const p of pillarProgress) {
      pillarScores[p.pillar] = Number(p.currentScore);
    }
    const checks = {
      skillsAchieved: {
        required: requirements.skillAchievedCount || 0,
        current: achievedSkills.length,
        passed: achievedSkills.length >= (requirements.skillAchievedCount || 0)
      },
      pillarMinimums: {}
    };
    if (requirements.pillarMinimum) {
      for (const [pillar, minScore] of Object.entries(requirements.pillarMinimum)) {
        const current = pillarScores[pillar] || 0;
        checks.pillarMinimums[pillar] = {
          required: minScore,
          current,
          passed: current >= minScore
        };
      }
    }
    const allPillarsPassed = Object.values(checks.pillarMinimums).every((p) => p.passed);
    const ready = checks.skillsAchieved.passed && allPillarsPassed;
    res.json({
      ready,
      currentLevel: level,
      nextLevel: level.promotionToLevelId,
      checks,
      achievedSkills,
      totalSkillsRequired: levelSkillsData.length
    });
  } catch (error) {
    console.error("Error checking readiness:", error);
    res.status(500).json({ error: "Failed to check readiness" });
  }
});
