async function processSkillScores(playerId, sessionId, coachId, skillRatings) {
  const alpha = 0.4;
  for (const [skillId, score] of Object.entries(skillRatings)) {
    if (score < 0 || score > 2) continue;
    const previousScores = await db.select().from(playerSkillScores2).where(and12(
      eq13(playerSkillScores2.playerId, playerId),
      eq13(playerSkillScores2.skillId, skillId)
    )).orderBy(desc9(playerSkillScores2.createdAt)).limit(1);
    let movingAverage;
    let observationCount;
    if (previousScores.length > 0) {
      const prev = previousScores[0];
      const oldAvg = Number(prev.movingAverage) || score;
      movingAverage = alpha * score + (1 - alpha) * oldAvg;
      observationCount = (prev.observationCount || 0) + 1;
    } else {
      movingAverage = score;
      observationCount = 1;
    }
    await db.insert(playerSkillScores2).values({
      playerId,
      skillId,
      score,
      sessionId,
      coachId,
      movingAverage: movingAverage.toFixed(2),
      observationCount
    });
    if (coachId) {
      checkForScoringAnomaly(coachId, skillId, sessionId, playerId, score).catch((err) => {
        console.error("Error running calibration anomaly check:", err);
      });
    }
  }
}
