async function fireQuestEvent(playerId, action) {
  if (!playerId) return;
  try {
    const activeQuests = await db.select({
      quest: playerQuests,
      template: questTemplates
    }).from(playerQuests).innerJoin(
      questTemplates,
      eq15(playerQuests.questTemplateId, questTemplates.id)
    ).where(
      and14(
        eq15(playerQuests.playerId, playerId),
        eq15(playerQuests.status, "active"),
        eq15(questTemplates.targetAction, action),
        eq15(questTemplates.isActive, true)
      )
    );
    for (const { quest, template } of activeQuests) {
      const newProgress = Math.min(
        (quest.currentProgress || 0) + 1,
        quest.targetProgress
      );
      const isComplete = newProgress >= quest.targetProgress;
      await db.update(playerQuests).set({
        currentProgress: newProgress,
        status: isComplete ? "completed" : "active",
        completedAt: isComplete ? /* @__PURE__ */ new Date() : null
      }).where(eq15(playerQuests.id, quest.id));
      if (isComplete && template.questType === "daily") {
        const today = (/* @__PURE__ */ new Date()).toISOString().split("T")[0];
        await db.update(dailyQuestSlots).set({
          completedCount: sql15`completed_count + 1`,
          allCompleted: sql15`completed_count + 1 >= 3`,
          bonusUnlocked: sql15`completed_count + 1 >= 3`
        }).where(
          and14(
            eq15(dailyQuestSlots.playerId, playerId),
            eq15(dailyQuestSlots.slotDate, today)
          )
        );
      }
    }
  } catch (err) {
    console.error("[QuestEvents] Error firing quest event:", action, err);
  }
}

