import { eq as eq20, and as and19, desc as desc15, or as or9, sql as sql20 } from "drizzle-orm";
var router10 = Router9();
router10.get("/api/parent/children", authMiddlewareWithFreshData, async (req2, res) => {
  try {
    const userId = req2.user.id;
    const children = await db.select({
      id: players.id,
      firstName: players.firstName,
      lastName: players.lastName,
      photoUrl: players.photoUrl,
      ballLevel: players.ballLevel
    }).from(players).where(eq20(players.parentUserId, userId));
    const childrenWithProgress = await Promise.all(children.map(async (child) => {
      const [level] = await db.select({
        levelId: playerBallLevels.levelId,
        status: playerBallLevels.status,
        progressPercentage: playerBallLevels.progressPercentage
      }).from(playerBallLevels).where(and19(
        eq20(playerBallLevels.playerId, child.id),
        or9(
          eq20(playerBallLevels.status, "active"),
          eq20(playerBallLevels.status, "trial")
        )
      )).orderBy(desc15(playerBallLevels.activatedAt)).limit(1);
      return {
        ...child,
        currentLevel: level?.levelId || child.ballLevel || "RED_3",
        levelStatus: level?.status || "active",
        progressPercentage: level?.progressPercentage || 0
      };
    }));
    res.json(childrenWithProgress);
  } catch (error) {
    console.error("Error fetching children:", error);
    res.status(500).json({ error: "Failed to fetch children" });
  }
});
router10.get("/api/parent/children/:playerId/progress", authMiddlewareWithFreshData, async (req2, res) => {
  try {
    const userId = req2.user.id;
    const { playerId } = req2.params;
    const [child] = await db.select().from(players).where(and19(
      eq20(players.id, playerId),
      eq20(players.parentUserId, userId)
    ));
    if (!child) {
      return res.status(403).json({ error: "Access denied" });
    }
    const [currentLevel] = await db.select({
      levelId: playerBallLevels.levelId,
      status: playerBallLevels.status,
      progressPercentage: playerBallLevels.progressPercentage,
      trialEndsAt: playerBallLevels.trialEndsAt
    }).from(playerBallLevels).where(and19(
      eq20(playerBallLevels.playerId, playerId),
      or9(
        eq20(playerBallLevels.status, "active"),
        eq20(playerBallLevels.status, "trial")
      )
    )).orderBy(desc15(playerBallLevels.activatedAt)).limit(1);
    const levelInfo = currentLevel ? await db.select().from(ballLevels).where(eq20(ballLevels.id, currentLevel.levelId)) : [];
    const recentEvents = await db.select().from(levelUpEvents).where(eq20(levelUpEvents.playerId, playerId)).orderBy(desc15(levelUpEvents.triggeredAt)).limit(5);
    res.json({
      player: {
        id: child.id,
        firstName: child.firstName,
        lastName: child.lastName,
        photoUrl: child.photoUrl
      },
      currentLevel: currentLevel || { levelId: child.ballLevel || "RED_3", status: "active", progressPercentage: 0 },
      levelDetails: levelInfo[0] || null,
      recentEvents
    });
  } catch (error) {
    console.error("Error fetching child progress:", error);
    res.status(500).json({ error: "Failed to fetch progress" });
  }
});
router10.get("/api/parent/children/:playerId/sessions", authMiddlewareWithFreshData, async (req2, res) => {
  try {
    const userId = req2.user.id;
    const { playerId } = req2.params;
    const { limit = "10" } = req2.query;
    const [child] = await db.select().from(players).where(and19(
      eq20(players.id, playerId),
      eq20(players.parentUserId, userId)
    ));
    if (!child) {
      return res.status(403).json({ error: "Access denied" });
    }
    const recentSessions = await db.select({
      id: sessions.id,
      date: sessions.date,
      startTime: sessions.startTime,
      endTime: sessions.endTime,
      status: sessions.status,
      type: sessions.type
    }).from(sessions).where(sql20`${playerId} = ANY(${sessions.playerIds})`).orderBy(desc15(sessions.date)).limit(parseInt(limit));
    const sessionsWithFeedback = await Promise.all(recentSessions.map(async (session) => {
      const [feedback] = await db.select().from(sessionFeedback).where(and19(
        eq20(sessionFeedback.sessionId, session.id),
        eq20(sessionFeedback.playerId, playerId)
      ));
      return {
        ...session,
        feedback: feedback || null
      };
    }));
    res.json(sessionsWithFeedback);
  } catch (error) {
    console.error("Error fetching child sessions:", error);
    res.status(500).json({ error: "Failed to fetch sessions" });
  }
});
router10.get("/api/parent/children/:playerId/feedback", authMiddlewareWithFreshData, async (req2, res) => {
  try {
    const userId = req2.user.id;
    const { playerId } = req2.params;
    const { limit = "10" } = req2.query;
    const [child] = await db.select().from(players).where(and19(
      eq20(players.id, playerId),
      eq20(players.parentUserId, userId)
    ));
    if (!child) {
      return res.status(403).json({ error: "Access denied" });
    }
    const feedback = await db.select({
      id: sessionFeedback.id,
      sessionId: sessionFeedback.sessionId,
      rating: sessionFeedback.rating,
      feedback: sessionFeedback.feedback,
      parentTaalFeedback: sessionFeedback.parentTaalFeedback,
      createdAt: sessionFeedback.createdAt
    }).from(sessionFeedback).where(eq20(sessionFeedback.playerId, playerId)).orderBy(desc15(sessionFeedback.createdAt)).limit(parseInt(limit));
    res.json(feedback);
  } catch (error) {
    console.error("Error fetching feedback:", error);
    res.status(500).json({ error: "Failed to fetch feedback" });
  }
});
router10.get("/api/parent/messages", authMiddlewareWithFreshData, async (req2, res) => {
  try {
    const userId = req2.user.id;
    const parentMessages = await db.select({
      id: messages.id,
      content: messages.content,
      createdAt: messages.createdAt,
      readAt: messages.readAt,
      senderName: users.displayName
    }).from(messages).leftJoin(users, eq20(messages.senderId, users.id)).where(eq20(messages.receiverId, userId)).orderBy(desc15(messages.createdAt)).limit(20);
    res.json(parentMessages);
  } catch (error) {
    console.error("Error fetching parent messages:", error);
    res.status(500).json({ error: "Failed to fetch messages" });
  }
});
var parent_dashboard_default = router10;

