router11.post("/find-or-create-opponent", async (req2, res) => {
  try {
    const { name } = req2.body;
    const user = req2.user;
    const scopedAcademyId = user.role === "platform_owner" ? req2.body.academyId || user.academyId : user.academyId;
    if (!name || !name.trim()) {
      return res.status(400).json({ error: "Opponent name is required" });
    }
    const trimmedName = name.trim();
    const existingPlayers = await db.select({ id: players.id, name: players.name }).from(players).where(and21(
      sql21`LOWER(${players.name}) = LOWER(${trimmedName})`,
      scopedAcademyId ? eq22(players.academyId, scopedAcademyId) : sql21`true`
    )).limit(5);
    if (existingPlayers.length > 0) {
      return res.json({
        opponent: existingPlayers[0],
        created: false,
        suggestions: existingPlayers
      });
    }
    const [newOpponent] = await db.insert(players).values({
      name: trimmedName,
      academyId: scopedAcademyId || null,
      isAdult: true,
      glowMmr: 1e3,
      glowRank: 9
    }).returning({ id: players.id, name: players.name });
    res.json({
      opponent: newOpponent,
      created: true,
      suggestions: []
    });
  } catch (error) {
    console.error("Error finding/creating opponent:", error);
    res.status(500).json({ error: "Failed to process opponent" });
  }
});
