            playerName = otherPlayer?.name ?? null;
            otherPlayerId = other.playerId;
            const [otherUser] = await db.select({ id: users.id }).from(users).where(eq29(users.playerId, other.playerId)).limit(1);
            otherPlayerUserId = otherUser?.id ?? null;
