    const xpSummary = recentXp.length > 0 ? recentXp.map((x) => `${x.xpAmount > 0 ? "+" : ""}${x.xpAmount} XP (${x.source})${x.description ? ": " + x.description : ""}`).join("\n") : "No recent XP history.";
    const glowWeakSummary = weakGlowAreas.length > 0 ? weakGlowAreas.map((w) => `${w.skillName} (${w.pillar} pillar, avg score: ${w.movingAverage ?? "new"})`).join("\n") : "No Glow Score skill data yet.";
    const playerName = player2.name || "this player";
