router21.post("/api/coach/travel-times", authMiddlewareWithFreshData, requireAcademy, async (req2, res) => {
  try {
    const coachId = req2.user?.coachId;
    const academyId = req2.user?.academyId;
    if (!coachId || !academyId) {
      return res.status(403).json({ error: "Coach access required" });
    }
    const { fromLocationId, toLocationId, travelTimeMinutes } = req2.body;
    if (!fromLocationId || !toLocationId || typeof travelTimeMinutes !== "number") {
      return res.status(400).json({ error: "Missing required fields" });
    }
    if (fromLocationId === toLocationId) {
      return res.status(400).json({ error: "Cannot set travel time to same location" });
    }
    const directions = [
      { from: fromLocationId, to: toLocationId },
      { from: toLocationId, to: fromLocationId }
      // Reverse direction
    ];
    const results = [];
    for (const dir of directions) {
      const existing2 = await db.select().from(locationTravelTimes).where(and29(
        eq32(locationTravelTimes.coachId, coachId),
        eq32(locationTravelTimes.academyId, academyId),
        eq32(locationTravelTimes.fromLocationId, dir.from),
        eq32(locationTravelTimes.toLocationId, dir.to)
      )).limit(1);
      let result;
      if (existing2.length > 0) {
        [result] = await db.update(locationTravelTimes).set({
          travelTimeMinutes,
          updatedAt: /* @__PURE__ */ new Date()
        }).where(eq32(locationTravelTimes.id, existing2[0].id)).returning();
      } else {
        [result] = await db.insert(locationTravelTimes).values({
          coachId,
          academyId,
          fromLocationId: dir.from,
          toLocationId: dir.to,
          travelTimeMinutes
        }).returning();
      }
      results.push(result);
    }
    res.json({ created: results, bidirectional: true });
  } catch (error) {
    console.error("Create travel time error:", error);
    res.status(500).json({ error: "Failed to create travel time" });
  }
});
