router22.get("/api/player/leaderboard", authMiddlewareWithFreshData, requireFeatureUnlock("glow_leaderboard"), async (req2, res) => {
  try {
    const academyId = req2.user.academyId;
    const playerId = req2.user.playerId;
    const scope = req2.query.scope || "academy";
    const category = req2.query.category || "glow_score";
    const conditions = [eq34(players.status, "active")];
    if (scope === "academy" && academyId) {
      conditions.push(eq34(players.academyId, academyId));
    }
    if (category === "dss_rating") {
      conditions.push(eq34(players.isAdult, true));
      conditions.push(sql28`COALESCE(${players.glowMmr}, 0) > 0`);
    } else if (category === "ball_level") {
      conditions.push(sql28`${players.ballLevel} IS NOT NULL`);
    }
    let topPlayers;
    if (category === "xp") {
      topPlayers = await db.select({
        id: players.id,
        name: players.name,
        photoUrl: players.profilePhotoUrl,
        level: players.level,
        glowScore: players.glowScore,
        xp: players.xp,
        ballLevel: players.ballLevel,
        glowMmr: players.glowMmr,
        streak: players.consecutiveDays
      }).from(players).where(and31(...conditions)).orderBy(desc23(players.xp)).limit(50);
    } else if (category === "dss_rating") {
      topPlayers = await db.select({
        id: players.id,
        name: players.name,
        photoUrl: players.profilePhotoUrl,
        level: players.level,
        glowScore: players.glowScore,
        xp: players.xp,
        ballLevel: players.ballLevel,
        glowMmr: players.glowMmr,
        streak: players.consecutiveDays
      }).from(players).where(and31(...conditions)).orderBy(desc23(players.glowMmr)).limit(50);
    } else if (category === "ball_level") {
      topPlayers = await db.select({
        id: players.id,
        name: players.name,
        photoUrl: players.profilePhotoUrl,
        level: players.level,
        glowScore: players.glowScore,
        xp: players.xp,
        ballLevel: players.ballLevel,
        glowMmr: players.glowMmr,
        streak: players.consecutiveDays
      }).from(players).where(and31(...conditions)).orderBy(desc23(players.glowScore)).limit(50);
      const ballOrder = { yellow: 1, green: 2, orange: 3, red: 4 };
      topPlayers.sort((a, b) => (ballOrder[a.ballLevel] || 5) - (ballOrder[b.ballLevel] || 5));
    } else {
      topPlayers = await db.select({
        id: players.id,
        name: players.name,
        photoUrl: players.profilePhotoUrl,
        level: players.level,
        glowScore: players.glowScore,
        xp: players.xp,
        ballLevel: players.ballLevel,
        glowMmr: players.glowMmr,
        streak: players.consecutiveDays
      }).from(players).where(and31(...conditions)).orderBy(desc23(players.glowScore)).limit(50);
    }
    let myRank = 0;
    if (playerId) {
      const playerIndex = topPlayers.findIndex((p) => p.id === playerId);
      if (playerIndex >= 0) {
        myRank = playerIndex + 1;
      } else {
        myRank = topPlayers.length + 1;
      }
    }
    const currentPlayer = playerId ? topPlayers.find((p) => p.id === playerId) : null;
    const formatDssRating2 = (mmr) => {
      if (!mmr) return null;
      return ((mmr - 1e3) / 1e3 * 3 + 3).toFixed(1);
    };
    res.json({
      scope,
      category,
      myRank,
      currentPlayer: currentPlayer ? {
        ...currentPlayer,
        rank: myRank,
        dssRating: formatDssRating2(currentPlayer.glowMmr)
      } : null,
      rankings: topPlayers.map((p, idx) => ({
        rank: idx + 1,
        id: p.id,
        name: p.name,
        photoUrl: p.photoUrl,
        level: p.level || 1,
        glowScore: p.glowScore || 0,
        xp: p.xp || 0,
        ballLevel: p.ballLevel,
        dssRating: formatDssRating2(p.glowMmr),
        streak: p.streak || 0,
        isCurrentPlayer: p.id === playerId
      }))
    });
  } catch (error) {
    console.error("Error fetching leaderboard:", error);
    res.status(500).json({ error: "Failed to fetch leaderboard" });
  }
});
