router22.post("/api/admin/recalculate-v3-debts", authMiddlewareWithFreshData, requireRole("platform_owner"), async (req2, res) => {
  try {
    console.log("[V3DebtFix] Starting recalculation of V3 debts...");
    const v3Debts = await db.select().from(creditTransactions).where(and31(
      eq34(creditTransactions.reason, "session_debt"),
      isNull7(creditTransactions.sessionId)
    ));
    console.log(`[V3DebtFix] Found ${v3Debts.length} V3 debt transactions to review`);
    const results = [];
    for (const debt of v3Debts) {
      if (!debt.playerId) continue;
      const creditType = debt.creditType || "group";
      const oldDebtAmount = Math.abs(debt.amount);
      const sessionTypesForCredit = creditType === "group" ? ["group"] : creditType === "semi_private" ? ["semi_private", "semi-private"] : ["private"];
      const presentSessions = await db.select({ count: sql28`count(*)` }).from(sessionPlayers).innerJoin(sessions, eq34(sessionPlayers.sessionId, sessions.id)).where(and31(
        eq34(sessionPlayers.playerId, debt.playerId),
        eq34(sessionPlayers.attendanceStatus, "present"),
        inArray13(sessions.sessionType, sessionTypesForCredit)
      ));
      const presentCount = Number(presentSessions[0]?.count || 0);
      const playerPackages = await db.select({
        totalCredits: sql28`COALESCE(SUM(total_credits), 0)`
      }).from(packages).where(and31(
        eq34(packages.playerId, debt.playerId),
        eq34(packages.creditType, creditType)
      ));
      const totalPurchased = Number(playerPackages[0]?.totalCredits || 0);
      const newDebtAmount = Math.max(0, presentCount - totalPurchased);
      const change = oldDebtAmount - newDebtAmount;
      if (change !== 0) {
        if (newDebtAmount === 0) {
          await db.update(creditTransactions).set({
            amount: 0,
            metadata: {
              ...debt.metadata || {},
              cancelled: true,
              recalculatedAt: (/* @__PURE__ */ new Date()).toISOString(),
              oldAmount: debt.amount,
              reason: "v3_debt_recalculation"
            }
          }).where(eq34(creditTransactions.id, debt.id));
        } else {
          await db.update(creditTransactions).set({
            amount: -newDebtAmount,
            metadata: {
              ...debt.metadata || {},
              recalculatedAt: (/* @__PURE__ */ new Date()).toISOString(),
              oldAmount: debt.amount,
              presentCount,
              totalPurchased,
              reason: "v3_debt_recalculation"
            }
          }).where(eq34(creditTransactions.id, debt.id));
        }
        results.push({
          playerId: debt.playerId,
          creditType,
          oldDebt: oldDebtAmount,
          newDebt: newDebtAmount,
          change
        });
        console.log(`[V3DebtFix] Player ${debt.playerId.slice(0, 8)}: ${creditType} debt ${oldDebtAmount} -> ${newDebtAmount} (change: ${change})`);
      }
    }
    console.log(`[V3DebtFix] Complete. Updated ${results.length} debt records`);
    res.json({
      success: true,
      message: `Recalculated ${results.length} V3 debt records`,
      totalCreditsRestored: results.reduce((sum2, r) => sum2 + r.change, 0),
      details: results
    });
  } catch (error) {
    console.error("[V3DebtFix] Error:", error);
    res.status(500).json({ error: "Failed to recalculate V3 debts" });
  }
});
router22.post("/api/admin/fix-vacation-v3-debts", authMiddlewareWithFreshData, requireRole("platform_owner"), async (req2, res) => {
  try {
    console.log("[VacationV3Fix] Starting vacation debt adjustment...");
    const v3Debts = await db.select().from(creditTransactions).where(and31(
      eq34(creditTransactions.reason, "session_debt"),
      isNull7(creditTransactions.sessionId)
    ));
    console.log(`[VacationV3Fix] Found ${v3Debts.length} V3 debt transactions`);
    const results = [];
    for (const debt of v3Debts) {
      if (!debt.playerId) continue;
      const meta = debt.metadata;
      if (meta?.cancelled) continue;
      const creditType = debt.creditType || "group";
      const oldDebtAmount = Math.abs(debt.amount);
      const sessionTypesForCredit = creditType === "group" ? ["group"] : creditType === "semi_private" ? ["semi_private", "semi-private"] : ["private"];
      const vacationSessions = await db.select({ count: sql28`count(*)` }).from(sessionPlayers).innerJoin(sessions, eq34(sessionPlayers.sessionId, sessions.id)).where(and31(
        eq34(sessionPlayers.playerId, debt.playerId),
        eq34(sessionPlayers.attendanceStatus, "vacation"),
        inArray13(sessions.sessionType, sessionTypesForCredit)
      ));
      const vacationCount = Number(vacationSessions[0]?.count || 0);
      if (vacationCount === 0) continue;
      const newDebtAmount = Math.max(0, oldDebtAmount - vacationCount);
      if (newDebtAmount === 0) {
        await db.update(creditTransactions).set({
          amount: 0,
          metadata: {
            ...meta || {},
            cancelled: true,
            vacationAdjustment: vacationCount,
            adjustedAt: (/* @__PURE__ */ new Date()).toISOString(),
            oldAmount: debt.amount
          }
        }).where(eq34(creditTransactions.id, debt.id));
      } else {
        await db.update(creditTransactions).set({
          amount: -newDebtAmount,
          metadata: {
            ...meta || {},
            vacationAdjustment: vacationCount,
            adjustedAt: (/* @__PURE__ */ new Date()).toISOString(),
            oldAmount: debt.amount
          }
        }).where(eq34(creditTransactions.id, debt.id));
      }
      results.push({
        playerId: debt.playerId,
        creditType,
        oldDebt: oldDebtAmount,
        newDebt: newDebtAmount,
        vacationCount
      });
      console.log(`[VacationV3Fix] Player ${debt.playerId.slice(0, 8)}: ${creditType} debt ${oldDebtAmount} -> ${newDebtAmount} (vacations: ${vacationCount})`);
    }
    console.log(`[VacationV3Fix] Complete. Adjusted ${results.length} debt records`);
    res.json({
      success: true,
      message: `Adjusted ${results.length} V3 debt records for vacation sessions`,
      totalCreditsRestored: results.reduce((sum2, r) => sum2 + (r.oldDebt - r.newDebt), 0),
      details: results
    });
  } catch (error) {
    console.error("[VacationV3Fix] Error:", error);
    res.status(500).json({ error: "Failed to fix vacation V3 debts" });
  }
});
router22.post("/api/admin/recalculate-all-debts", authMiddlewareWithFreshData, requireRole("platform_owner"), async (req2, res) => {
  try {
    console.log("[RecalculateDebts] Starting full recalculation of all player debts...");
    const sessionsNeedingDebt = await db.execute(sql28`
        SELECT 
          sp.id as session_player_id,
          sp.player_id,
          sp.session_id,
          sp.attendance_status,
          sp.credit_deducted_at,
          sp.credit_transaction_id,
          s.session_type,
          s.academy_id,
          s.start_time as session_date
        FROM session_players sp
        JOIN sessions s ON s.id = sp.session_id
        WHERE sp.attendance_status IN ('present', 'late')
          AND s.status = 'completed'
        ORDER BY sp.player_id, s.start_time
      `);
    console.log(`[RecalculateDebts] Found ${sessionsNeedingDebt.rows.length} present/late session records`);
    const v3DebtsResult = await db.execute(sql28`
        UPDATE credit_transactions 
        SET amount = 0,
            metadata = jsonb_set(
              COALESCE(metadata, '{}'::jsonb), 
              '{cancelled}', 
              'true'::jsonb
            ) || jsonb_build_object('cancelledAt', NOW()::text, 'cancelReason', 'recalculate_all_debts')
        WHERE reason = 'session_debt' 
          AND session_id IS NULL
          AND (metadata->>'cancelled')::boolean IS NOT TRUE
        RETURNING id
      `);
    console.log(`[RecalculateDebts] Cancelled ${v3DebtsResult.rows.length} V3 aggregated debt records`);
    const playerDebts = /* @__PURE__ */ new Map();
    for (const row of sessionsNeedingDebt.rows) {
      const playerId = row.player_id;
      const sessionType = row.session_type || "group";
      const creditType = sessionType.includes("private") && !sessionType.includes("semi") ? "private" : sessionType.includes("semi") ? "semi_private" : "group";
      if (!playerDebts.has(playerId)) {
        playerDebts.set(playerId, /* @__PURE__ */ new Map());
      }
      const playerMap = playerDebts.get(playerId);
      if (!playerMap.has(creditType)) {
        playerMap.set(creditType, { playerId, creditType, sessions: [] });
      }
      playerMap.get(creditType).sessions.push(row);
    }
    const results = [];
    for (const [playerId, creditTypes] of playerDebts) {
      for (const [creditType, data] of creditTypes) {
        const packagesResult = await db.execute(sql28`
            SELECT COALESCE(SUM(remaining_credits), 0) as total_credits
            FROM packages 
            WHERE player_id = ${playerId}
              AND status = 'active'
              AND (credit_type = ${creditType} OR credit_type IS NULL)
          `);
        const consumedResult = await db.execute(sql28`
            SELECT COUNT(*) as consumed
            FROM credit_transactions
            WHERE player_id = ${playerId}
              AND credit_type = ${creditType}
              AND reason = 'session_consumed'
              AND package_id IS NOT NULL
          `);
        const availableCredits = Number(packagesResult.rows[0]?.total_credits || 0);
        const alreadyConsumed = Number(consumedResult.rows[0]?.consumed || 0);
        const presentCount = data.sessions.length;
        const totalCreditsEver = availableCredits + alreadyConsumed;
        const debtAmount = Math.max(0, presentCount - totalCreditsEver);
        if (debtAmount > 0) {
          const debtId = crypto.randomUUID();
          await db.execute(sql28`
              INSERT INTO credit_transactions (
                id, player_id, academy_id, type, credit_type, amount, reason, metadata
              )
              VALUES (
                ${debtId},
                ${playerId},
                'default-academy',
                'debit',
                ${creditType},
                ${-debtAmount},
                'session_debt',
                ${JSON.stringify({
            recalculatedAt: (/* @__PURE__ */ new Date()).toISOString(),
            presentCount,
            totalCreditsEver,
            availableCredits,
            alreadyConsumed,
            description: `Recalculated debt: ${presentCount} sessions - ${totalCreditsEver} credits = ${debtAmount} owed`
          })}::jsonb
              )
            `);
          console.log(`[RecalculateDebts] Player ${playerId.slice(0, 8)}: ${creditType} debt = ${debtAmount} (present: ${presentCount}, credits: ${totalCreditsEver})`);
        }
        results.push({
          playerId,
          creditType,
          presentCount,
          availableCredits: totalCreditsEver,
          debtCreated: debtAmount
        });
      }
    }
    const totalDebtCreated = results.reduce((sum2, r) => sum2 + r.debtCreated, 0);
    console.log(`[RecalculateDebts] Complete. Created ${totalDebtCreated} total debt across ${results.filter((r) => r.debtCreated > 0).length} player/type combos`);
    res.json({
      success: true,
      message: `Recalculated debts for ${playerDebts.size} players`,
      v3DebtsCancelled: v3DebtsResult.rows.length,
      totalDebtCreated,
      details: results.filter((r) => r.debtCreated > 0)
    });
  } catch (error) {
    console.error("[RecalculateDebts] Error:", error);
    res.status(500).json({ error: "Failed to recalculate debts" });
  }
});
router22.get("/api/admin/dashboard/operations", authMiddlewareWithFreshData, requireRole("admin", "academy_owner", "platform_owner"), async (req2, res) => {
  try {
    const academyId = req2.user?.academyId;
    if (!academyId) {
      return res.status(400).json({ error: "Academy context required" });
    }
    const academy = await storage.getAcademy(academyId);
    const settings = await storage.getAcademySettings(academyId);
    const players8 = await storage.getPlayersByAcademy(academyId);
    const coaches15 = await storage.getCoachesByAcademy(academyId);
    const allSessions = await storage.getSessionsByAcademy(academyId);
    const dateParam = req2.query.date;
    const now2 = dateParam ? new Date(dateParam) : /* @__PURE__ */ new Date();
    const DUBAI_OFFSET = 4;
    const dubaiNow = new Date(now2.getTime() + DUBAI_OFFSET * 60 * 60 * 1e3);
    const todayStart = new Date(dubaiNow);
    todayStart.setHours(0, 0, 0, 0);
    const todayEnd = new Date(dubaiNow);
    todayEnd.setHours(23, 59, 59, 999);
    const todaySessions = allSessions.filter((s) => {
      const sessionDate2 = new Date(s.startTime);
      return sessionDate2 >= todayStart && sessionDate2 <= todayEnd;
    });
    const completedToday = todaySessions.filter((s) => s.status === "completed");
    const inProgressToday = todaySessions.filter((s) => s.status === "in_progress");
    const upcomingToday = todaySessions.filter((s) => {
      const sessionStart = new Date(s.startTime);
      return s.status !== "completed" && s.status !== "in_progress" && sessionStart > now2;
    });
    const activeCoachIds = new Set(inProgressToday.map((s) => s.coachId));
    const activeCoachesNow = coaches15.filter((c) => activeCoachIds.has(c.id)).length;
    const nextSession = upcomingToday[0];
    const nextSessionIn = nextSession ? Math.max(0, Math.floor((new Date(nextSession.startTime).getTime() - now2.getTime()) / 6e4)) : 0;
    const sessionQueue = todaySessions.slice(0, 10).map((s) => {
      const coach = coaches15.find((c) => c.id === s.coachId);
      const sessionPlayers9 = players8.filter((p) => p.coachId === s.coachId);
      const sessionTime = new Date(s.startTime);
      let status = "upcoming";
      if (s.status === "completed") status = "completed";
      else if (s.status === "in_progress") status = "in_progress";
      else if (sessionTime <= now2) status = "in_progress";
      return {
        id: s.id,
        title: s.title || "Training Session",
        time: sessionTime.toLocaleTimeString("en-US", { hour: "2-digit", minute: "2-digit", hour12: false }),
        coachName: coach?.name || "Unassigned",
        playerCount: sessionPlayers9.length,
        status
      };
    });
    const checkIns = todaySessions.slice(0, 5).map((s, idx) => {
      const player2 = players8[idx % players8.length];
      return {
        id: `checkin-${s.id}-${idx}`,
        playerName: player2?.name || "Player",
        sessionTitle: s.title || "Training Session",
        time: new Date(s.startTime).toLocaleTimeString("en-US", { hour: "2-digit", minute: "2-digit", hour12: false }),
        status: idx < 2 ? "pending" : "confirmed"
      };
    });
    const taskAlerts = [];
    const unpaidPlayers = players8.filter((p) => (p.balanceDue || 0) > 0);
    unpaidPlayers.slice(0, 2).forEach((p) => {
      taskAlerts.push({
        id: `payment-${p.id}`,
        type: "payment",
        title: "Outstanding Payment",
        description: `${p.name} - ${settings?.currency || "AED"} ${p.balanceDue || 0}`,
        actionLabel: "Remind"
      });
    });
    if (upcomingToday.length > 0 && nextSessionIn < 15) {
      taskAlerts.push({
        id: "session-starting",
        type: "urgent",
        title: "Session Starting Soon",
        description: `${upcomingToday[0].title || "Session"} starts in ${nextSessionIn} minutes`,
        actionLabel: "View"
      });
    }
    const currency = settings?.currency || "AED";
    res.json({
      academy: academy ? {
        id: academy.id,
        name: academy.name,
        currency
      } : null,
      liveStats: {
        activeSessions: inProgressToday.length,
        waitingCheckIns: checkIns.filter((c) => c.status === "pending").length,
        activeCoaches: activeCoachesNow,
        nextSessionIn
      },
      todayOperations: {
        totalSessions: todaySessions.length,
        completedSessions: completedToday.length,
        inProgressSessions: inProgressToday.length,
        upcomingSessions: upcomingToday.length
      },
      sessionQueue,
      checkIns,
      taskAlerts,
      quickStats: {
        todayPlayers: Math.min(todaySessions.length * 3, players8.length),
        todayCoaches: coaches15.filter((c) => c.isActive !== false).length,
        attendanceRate: (() => {
          const nonCancelled = todaySessions.filter((s) => s.status !== "cancelled");
          return nonCancelled.length > 0 ? Math.round(completedToday.length / nonCancelled.length * 100) : 0;
        })(),
        completedSessions: completedToday.length
      }
    });
  } catch (error) {
    console.error("Admin operations dashboard error:", error);
    res.status(500).json({ error: "Failed to fetch operations dashboard data" });
  }
});
