router22.get("/api/admin/credits/diagnose/:playerId", adminRepairLimiter, authMiddlewareWithFreshData, requireRole("admin", "platform_owner"), async (req2, res) => {
  try {
    const { playerId } = req2.params;
    const sessionData = await db.execute(sql28`
        SELECT 
          sp.id as session_player_id,
          sp.session_id,
          sp.player_id,
          sp.attendance_status,
          sp.credit_deducted_at,
          sp.credit_transaction_id,
          s.session_type,
          s.status as session_status,
          s.start_time,
          s.series_id,
          cs.session_type as series_session_type,
          cs.title as series_title
        FROM session_players sp
        JOIN sessions s ON s.id = sp.session_id
        LEFT JOIN coaching_series cs ON cs.id = s.series_id
        WHERE sp.player_id = ${playerId}
          AND s.status = 'completed'
        ORDER BY s.start_time DESC
      `);
    const transactions = await db.execute(sql28`
        SELECT id, session_id, session_player_id, type, credit_type, amount, reason, created_at, package_id
        FROM credit_transactions 
        WHERE player_id = ${playerId}
        ORDER BY created_at DESC
      `);
    const packages15 = await db.execute(sql28`
        SELECT id, credit_type, total_credits, remaining_credits, status, expiry_date
        FROM packages 
        WHERE player_id = ${playerId}
        ORDER BY created_at DESC
      `);
    const sessions10 = sessionData.rows;
    const semiPrivateSessions = sessions10.filter(
      (s) => s.series_session_type === "semi_private" || s.session_type === "semi_private"
    );
    const semiPrivateWithCredit = semiPrivateSessions.filter((s) => s.credit_deducted_at);
    const semiPrivateWithoutCredit = semiPrivateSessions.filter((s) => !s.credit_deducted_at);
    const privateSessions = sessions10.filter(
      (s) => s.session_type === "private" || s.session_type === "private_adjusted"
    );
    const groupSessions = sessions10.filter((s) => s.session_type === "group");
    res.json({
      playerId,
      summary: {
        totalCompletedSessions: sessions10.length,
        semiPrivate: {
          total: semiPrivateSessions.length,
          creditDeducted: semiPrivateWithCredit.length,
          creditMissing: semiPrivateWithoutCredit.length
        },
        private: { total: privateSessions.length },
        group: { total: groupSessions.length }
      },
      missingSemiPrivateCredits: semiPrivateWithoutCredit.map((s) => ({
        sessionPlayerId: s.session_player_id,
        sessionId: s.session_id,
        sessionType: s.session_type,
        seriesType: s.series_session_type,
        attendanceStatus: s.attendance_status,
        startTime: s.start_time,
        seriesTitle: s.series_title
      })),
      packages: packages15.rows,
      recentTransactions: transactions.rows.slice(0, 20)
    });
  } catch (error) {
    console.error("[Diagnose] Error:", error);
    res.status(500).json({ error: "Failed to fetch diagnostics" });
  }
});
