router24.get("/api/academy/activity-feed", authMiddlewareWithFreshData, requireAcademy, async (req2, res) => {
  try {
    const academyId = req2.user.academyId;
    const limit = Math.min(parseInt(req2.query.limit) || 30, 50);
    const sevenDaysAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1e3);
    const academyPlayers = await db.select({
      id: players.id,
      name: players.name
    }).from(players).where(eq37(players.academyId, academyId));
    const playerIds = academyPlayers.map((p) => p.id);
    const playerMap = new Map(academyPlayers.map((p) => [p.id, p.name || "Player"]));
    if (playerIds.length === 0) {
      return res.json({ events: [] });
    }
    const [levelUps, xpEvents, completedSessions] = await Promise.all([
      // Level-up events (ball level promotions)
      db.select({
        id: levelUpEvents.id,
        playerId: levelUpEvents.playerId,
        toLevelId: levelUpEvents.toLevelId,
        fromLevelId: levelUpEvents.fromLevelId,
        xpAwarded: levelUpEvents.xpAwarded,
        titleUnlocked: levelUpEvents.titleUnlocked,
        createdAt: levelUpEvents.createdAt
      }).from(levelUpEvents).where(and34(
        inArray15(levelUpEvents.playerId, playerIds),
        gte17(levelUpEvents.createdAt, sevenDaysAgo)
      )).orderBy(desc26(levelUpEvents.createdAt)).limit(10),
      // XP events (level ups in XP system)
      db.select({
        id: playerXpEvents.id,
        playerId: playerXpEvents.playerId,
        actionSource: playerXpEvents.actionSource,
        xpAmount: playerXpEvents.xpAmount,
        triggeredLevelUp: playerXpEvents.triggeredLevelUp,
        newLevel: playerXpEvents.newLevel,
        levelAtEvent: playerXpEvents.levelAtEvent,
        createdAt: playerXpEvents.createdAt
      }).from(playerXpEvents).where(and34(
        inArray15(playerXpEvents.playerId, playerIds),
        gte17(playerXpEvents.createdAt, sevenDaysAgo)
      )).orderBy(desc26(playerXpEvents.createdAt)).limit(20),
      // Recently completed sessions
      db.select({
        id: sessions.id,
        title: sessions.title,
        sessionType: sessions.sessionType,
        startTime: sessions.startTime,
        status: sessions.status
      }).from(sessions).where(and34(
        eq37(sessions.academyId, academyId),
        eq37(sessions.status, "completed"),
        gte17(sessions.startTime, sevenDaysAgo)
      )).orderBy(desc26(sessions.startTime)).limit(10)
    ]);
    const events = [];
    for (const lu of levelUps) {
      const name = playerMap.get(lu.playerId) || "Player";
      events.push({
        id: `levelup-${lu.id}`,
        type: "level_up",
        icon: "arrow-up-circle",
        title: `${name} leveled up!`,
        description: lu.titleUnlocked ? `Unlocked title: ${lu.titleUnlocked}` : `Promoted to new ball level`,
        playerName: name,
        timestamp: lu.createdAt?.toISOString() || (/* @__PURE__ */ new Date()).toISOString(),
        xp: lu.xpAwarded || 0
      });
    }
    for (const xp of xpEvents) {
      const name = playerMap.get(xp.playerId) || "Player";
      if (xp.triggeredLevelUp && xp.newLevel) {
        events.push({
          id: `xplevel-${xp.id}`,
          type: "xp_level_up",
          icon: "star",
          title: `${name} reached Level ${xp.newLevel}!`,
          description: `Earned ${xp.xpAmount} XP from ${xp.actionSource.replace(/_/g, " ")}`,
          playerName: name,
          timestamp: xp.createdAt?.toISOString() || (/* @__PURE__ */ new Date()).toISOString(),
          xp: xp.xpAmount,
          level: xp.newLevel
        });
      } else if (xp.xpAmount >= 50) {
        events.push({
          id: `xp-${xp.id}`,
          type: "xp_earned",
          icon: "flash",
          title: `${name} earned ${xp.xpAmount} XP`,
          description: `From ${xp.actionSource.replace(/_/g, " ")}`,
          playerName: name,
          timestamp: xp.createdAt?.toISOString() || (/* @__PURE__ */ new Date()).toISOString(),
          xp: xp.xpAmount,
          level: xp.levelAtEvent
        });
      }
    }
    for (const s of completedSessions) {
      const typeLabel = s.sessionType === "private" ? "Private" : s.sessionType === "semi_private" ? "Semi-Private" : s.sessionType === "group" ? "Group" : s.sessionType === "private_adjusted" ? "Private (Adjusted)" : s.sessionType;
      events.push({
        id: `session-${s.id}`,
        type: "session_completed",
        icon: "checkmark-circle",
        title: `${typeLabel} session completed`,
        description: s.title || `${typeLabel} Session`,
        timestamp: s.startTime?.toISOString() || (/* @__PURE__ */ new Date()).toISOString()
      });
    }
    events.sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
    res.json({ events: events.slice(0, limit) });
  } catch (error) {
    console.error("Error fetching activity feed:", error);
    res.status(500).json({ error: "Failed to fetch activity feed" });
  }
});
