router26.get(
  "/auth/check-username/:username",
  async (req2, res) => {
    try {
      const { username } = req2.params;
      const normalizedUsername = username.toLowerCase().trim();
      if (normalizedUsername.length < 3) {
        return res.json({
          available: false,
          error: "Username must be at least 3 characters",
          suggestions: []
        });
      }
      if (!/^[a-z0-9_]+$/.test(normalizedUsername)) {
        return res.json({
          available: false,
          error: "Only letters, numbers, and underscores allowed",
          suggestions: []
        });
      }
      const existingUser = await storage.getUserByUsername(normalizedUsername);
      if (existingUser) {
        const suggestions = [];
        for (let i = 1; i <= 5; i++) {
          const suggestion = `${normalizedUsername}${i}`;
          const exists = await storage.getUserByUsername(suggestion);
          if (!exists) {
            suggestions.push(suggestion);
            if (suggestions.length >= 3) break;
          }
        }
        if (suggestions.length < 3) {
          for (let i = 10; i <= 99; i += 10) {
            const suggestion = `${normalizedUsername}_${i}`;
            const exists = await storage.getUserByUsername(suggestion);
            if (!exists) {
              suggestions.push(suggestion);
              if (suggestions.length >= 3) break;
            }
          }
        }
        return res.json({
          available: false,
          error: "Username already taken",
          suggestions
        });
      }
      res.json({ available: true, suggestions: [] });
    } catch (error) {
      console.error("Username check error:", error);
      res.status(500).json({
        available: false,
        error: "Failed to check username",
        suggestions: []
      });
    }
  }
);
router26.get("/auth/invite/:token", inviteLimiter, async (req2, res) => {
  try {
    const { token } = req2.params;
    const invite = await storage.getInviteByToken(token);
    if (invite) {
      if (invite.usedAt) {
        return res.status(400).json({ error: "This invite has already been used" });
      }
      if (/* @__PURE__ */ new Date() > new Date(invite.expiresAt)) {
        return res.status(400).json({ error: "This invite has expired" });
      }
      const academy = await storage.getAcademy(invite.academyId);
      return res.json({
        valid: true,
        role: invite.role,
        academyName: academy?.name || "Unknown Academy",
        email: invite.invitedEmail,
        invitedEmail: invite.invitedEmail,
        expiresAt: invite.expiresAt
      });
    }
    const playerInvite = await storage.getPlayerInvite(token);
    if (playerInvite) {
      if (playerInvite.status !== "pending") {
        return res.status(400).json({ error: "This invite has already been claimed or expired" });
      }
      const player2 = await storage.getPlayer(playerInvite.playerId);
      const academy = await storage.getAcademy(playerInvite.academyId);
      return res.json({
        valid: true,
        role: "player",
        academyName: academy?.name || "Unknown Academy",
        playerName: player2?.name || null,
        playerId: playerInvite.playerId,
        email: null,
        invitedEmail: null,
        isPlayerInvite: true
      });
    }
    return res.status(404).json({ error: "Invite not found" });
  } catch (error) {
    console.error("Invite validation error:", error);
    res.status(500).json({ error: "Failed to validate invite" });
  }
});
