router27.post(
  "/api/academy/reset",
  authMiddlewareWithFreshData,
  requireRole("academy_owner", "platform_owner"),
  async (req2, res) => {
    try {
      const academyId = req2.user.academyId;
      if (!academyId) {
        return res.status(400).json({ error: "Academy not found" });
      }
      const resetSchema = z8.object({
        confirmationCode: z8.literal("RESET"),
        resetTypes: z8.record(z8.string(), z8.boolean())
      });
      const parsedReset = resetSchema.safeParse(req2.body);
      if (!parsedReset.success) return res.status(400).json({ error: fromZodError6(parsedReset.error).message });
      const { resetTypes, confirmationCode } = parsedReset.data;
      if (confirmationCode !== "RESET") {
        return res.status(400).json({
          error: "Invalid confirmation code. Please type RESET to confirm."
        });
      }
      if (!resetTypes || typeof resetTypes !== "object") {
        return res.status(400).json({ error: "Please specify which data types to reset" });
      }
      const validTypes = [
        "sessions",
        "attendance",
        "payments",
        "progress",
        "feedback",
        "packages",
        "invoices",
        "players"
      ];
      const selectedTypes = Object.keys(resetTypes).filter(
        (key) => resetTypes[key] && validTypes.includes(key)
      );
      if (selectedTypes.length === 0) {
        return res.status(400).json({ error: "Please select at least one data type to reset" });
      }
      const result = await storage.resetAcademyData(academyId, resetTypes);
      console.log(
        `[Academy Reset] Academy ${academyId} reset: ${selectedTypes.join(", ")}`,
        result.deleted
      );
      res.json({
        success: true,
        message: `Academy data reset successfully`,
        deletedCounts: result.deleted
      });
    } catch (error) {
      console.error("Academy reset error:", error);
      res.status(500).json({ error: "Failed to reset academy data" });
    }
  }
);
