router33.patch(
  "/api/coach/series/:id",
  authMiddlewareWithFreshData,
  requireAcademy,
  async (req2, res) => {
    try {
      const { id } = req2.params;
      const coachId = req2.user.coachId;
      const existing2 = await storage.getCoachingSeriesById(id);
      if (!existing2) {
        return res.status(404).json({ error: "Series not found" });
      }
      if (existing2.coachId !== coachId) {
        return res.status(403).json({ error: "Not authorized to update this series" });
      }
      const updates = {};
      const allowedFields = [
        "title",
        "courtId",
        "locationId",
        "startTime",
        "duration",
        "ballLevel",
        "skillLevel",
        "maxPlayers",
        "sessionType",
        "xpPerSession",
        "vibe",
        "price",
        "seriesEndDate"
      ];
      const validSessionTypes = ["private", "semi_private", "group", "physical", "activity"];
      for (const field of allowedFields) {
        if (req2.body[field] !== void 0) {
          if (field === "sessionType" && !validSessionTypes.includes(req2.body[field])) {
            return res.status(400).json({ error: "Invalid sessionType value" });
          }
          updates[field] = field === "title" ? sanitizeTemplateName2(req2.body[field]) : req2.body[field];
        }
      }
      const updated = await storage.updateCoachingSeries(id, updates);
      if (updates.courtId) {
        const seriesSessions = await db.select({ id: sessions.id }).from(sessions).where(eq45(sessions.seriesId, id));
        if (seriesSessions.length > 0) {
          await db.update(sessions).set({ courtId: updates.courtId }).where(eq45(sessions.seriesId, id));
          console.log(
            `[SeriesUpdate] Updated court for ${seriesSessions.length} sessions in series ${id}`
          );
        }
      }
      res.json(updated);
    } catch (error) {
      console.error("Error updating coaching series:", error);
      res.status(500).json({ error: "Failed to update coaching series" });
    }
  }
);
