function parseNumericValue(value) {
  if (typeof value === "number" && !isNaN(value)) return value;
  if (typeof value === "string") {
    const cleaned = value.replace(/[^0-9.-]/g, "");
    const parsed = parseFloat(cleaned);
    return isNaN(parsed) ? 0 : parsed;
  }
  return 0;
}
function parseLineItems2(lineItemsJson) {
  if (!lineItemsJson) return [];
  try {
    const parsed = JSON.parse(lineItemsJson);
    const items = Array.isArray(parsed) ? parsed : parsed?.items || [];
    if (!Array.isArray(items)) return [];
    return items.map((item) => {
      const unitPrice = parseNumericValue(item.unitPrice);
      const quantity = parseNumericValue(item.quantity) || 1;
      const total = parseNumericValue(item.total) || unitPrice * quantity;
      return {
        description: item.description || "Item",
        quantity,
        unitPrice,
        total
      };
    });
  } catch {
    return [];
  }
}
function parseInvoiceMetadata(lineItemsJson) {
  if (!lineItemsJson) return {};
  try {
    const parsed = JSON.parse(lineItemsJson);
    if (Array.isArray(parsed)) return {};
    return {
      discount: parsed.discount ? Number(parsed.discount) : void 0,
      taxRate: parsed.taxRate ? Number(parsed.taxRate) : void 0,
      taxAmount: parsed.taxAmount ? Number(parsed.taxAmount) : void 0,
      subtotal: parsed.subtotal ? Number(parsed.subtotal) : void 0
    };
  } catch {
    return {};
  }
}

