      const debitSessionIds = new Set(
        allTransactions.filter((tx) => {
          const meta = tx.metadata;
          return Number(tx.amount) < 0 && tx.sessionId && tx.reason !== "debt_settlement" && meta?.cancelled !== true && meta?.expired !== true;
        }).map((tx) => tx.sessionId)
      );
      const missingSessions = attendedSessions.filter((sp) => !debitSessionIds.has(sp.sessionId)).filter((sp) => sessionDetails[sp.sessionId]?.status !== "cancelled").map((sp) => ({
        sessionId: sp.sessionId,
        sessionDetails: sessionDetails[sp.sessionId] || null
      }));
      res.json({
        player: { id: player2.id, name: player2.name },
        computedBalance: balance,
        transactions: txSummary,
        packages: allPackages.map((pkg2) => ({
          id: pkg2.id,
          creditType: pkg2.creditType,
          totalCredits: Number(pkg2.totalCredits),
          remainingCredits: Number(pkg2.remainingCredits),
          status: pkg2.status,
          expiryDate: pkg2.expiryDate,
          createdAt: pkg2.createdAt
        })),
        sessionPlayers: attendedSessions.map((sp) => ({
          sessionPlayerId: sp.id,
          sessionId: sp.sessionId,
          attendanceStatus: sp.attendanceStatus,
          sessionDetails: sessionDetails[sp.sessionId] || null,
          hasDebitTransaction: debitSessionIds.has(sp.sessionId)
        })),
        missingSessions,
        summary: {
          totalTransactions: allTransactions.length,
          activeTransactions: txSummary.filter((t) => t.includedInBalance).length,
          settledTransactions: txSummary.filter((t) => t.metadata?.settled === true).length,
          cancelledTransactions: txSummary.filter((t) => t.metadata?.cancelled === true).length,
          totalPackages: allPackages.length,
          totalSessionsAttended: attendedSessions.length,
          sessionsWithoutDebit: missingSessions.length
        }
      });
