router38.get(
  "/api/owner/operations",
  authMiddlewareWithFreshData,
  requireRole("owner", "academy_owner", "platform_owner"),
  async (req2, res) => {
    try {
      const academyId = req2.user?.academyId;
      const period = req2.query.period || "day";
      if (!academyId) {
        return res.status(400).json({ error: "Academy ID required" });
      }
      const dateParam = req2.query.date;
      const now2 = dateParam ? new Date(dateParam) : /* @__PURE__ */ new Date();
      const DUBAI_OFFSET = 4;
      const dubaiNow = new Date(
        now2.getTime() + DUBAI_OFFSET * 60 * 60 * 1e3
      );
      let startDate;
      let endDate = new Date(now2);
      endDate.setHours(23, 59, 59, 999);
      if (period === "day") {
        startDate = new Date(now2);
        startDate.setHours(0, 0, 0, 0);
      } else if (period === "week") {
        startDate = new Date(now2);
        startDate.setDate(now2.getDate() - now2.getDay());
        startDate.setHours(0, 0, 0, 0);
        endDate = new Date(startDate);
        endDate.setDate(startDate.getDate() + 6);
        endDate.setHours(23, 59, 59, 999);
      } else {
        startDate = new Date(now2.getFullYear(), now2.getMonth(), 1);
        endDate = new Date(now2.getFullYear(), now2.getMonth() + 1, 0);
        endDate.setHours(23, 59, 59, 999);
      }
      const dbCourts = await storage.getAllCourts(academyId);
      const allSessions = await storage.getAllSessions(academyId);
      const periodSessions = allSessions.filter((session) => {
        const sessionDate2 = new Date(session.date);
        return sessionDate2 >= startDate && sessionDate2 <= endDate;
      });
      const courtSessionsMap = {};
      for (const session of periodSessions) {
        const courtId = session.courtId || "unassigned";
        if (!courtSessionsMap[courtId]) {
          courtSessionsMap[courtId] = [];
        }
        courtSessionsMap[courtId].push(session);
      }
      const courtSchedule = dbCourts.map((court) => {
        const sessions10 = courtSessionsMap[court.id] || [];
        return {
          name: court.name,
          sessions: sessions10.map((s) => ({
            time: s.time || "TBD",
            coach: s.coachName || "Unassigned",
            status: s.status === "cancelled" ? "conflict" : "booked",
            date: s.date
          }))
        };
      });
      if (courtSessionsMap["unassigned"]?.length > 0) {
        courtSchedule.push({
          name: "No Court Assigned",
          sessions: courtSessionsMap["unassigned"].map((s) => ({
            time: s.time || "TBD",
            coach: s.coachName || "Unassigned",
            status: "conflict",
            date: s.date
          }))
        });
      }
      const totalSessions = periodSessions.length;
      const conflicts = periodSessions.filter(
        (s) => s.status === "cancelled" || !s.courtId
      ).length;
      const hourCounts = {};
      for (const session of periodSessions) {
        if (session.time) {
          const hour = parseInt(session.time.split(":")[0]) || 0;
          hourCounts[hour] = (hourCounts[hour] || 0) + 1;
        }
      }
      const peakHour = Object.entries(hourCounts).sort(
        (a, b) => b[1] - a[1]
      )[0];
      const peakHoursLabel = peakHour ? `${peakHour[0]}:00` : "N/A";
      const daysInPeriod = Math.ceil(
        (endDate.getTime() - startDate.getTime()) / (1e3 * 60 * 60 * 24)
      ) + 1;
      const maxPossibleSessions = dbCourts.length * daysInPeriod * 12;
      const utilization = maxPossibleSessions > 0 ? Math.round(totalSessions / maxPossibleSessions * 100) : 0;
      res.json({
        courts: courtSchedule,
        insights: {
          peakHours: peakHoursLabel,
          utilization,
          conflicts
        },
        period,
        dateRange: {
          start: startDate.toISOString(),
          end: endDate.toISOString()
        }
      });
    } catch (error) {
      console.error("Owner operations error:", error);
      res.status(500).json({ error: "Failed to fetch operations data" });
    }
  }
);
router38.get(
  "/api/owner/finance",
  authMiddlewareWithFreshData,
  requireRole("owner", "academy_owner", "platform_owner"),
  async (req2, res) => {
    try {
      const academyId = req2.user?.academyId;
      if (!academyId) {
        return res.status(400).json({ error: "Academy ID required" });
      }
      const allPayments = await storage.getPayments(academyId);
      const dateParam = req2.query.date;
      const now2 = dateParam ? new Date(dateParam) : /* @__PURE__ */ new Date();
      const DUBAI_OFFSET = 4;
      const dubaiNow = new Date(
        now2.getTime() + DUBAI_OFFSET * 60 * 60 * 1e3
      );
      const thisWeekStart = new Date(
        now2.getFullYear(),
        now2.getMonth(),
        now2.getDate() - now2.getDay()
      );
      const thisMonthStart = new Date(now2.getFullYear(), now2.getMonth(), 1);
      const lastMonthStart = new Date(
        now2.getFullYear(),
        now2.getMonth() - 1,
        1
      );
      const lastMonthEnd = new Date(now2.getFullYear(), now2.getMonth(), 0);
      const thisWeekPayments = allPayments.filter(
        (p) => p.status === "confirmed" && p.paymentDate && new Date(p.paymentDate) >= thisWeekStart
      );
      const thisMonthPayments = allPayments.filter(
        (p) => p.status === "confirmed" && p.paymentDate && new Date(p.paymentDate) >= thisMonthStart
      );
      const lastMonthPayments = allPayments.filter(
        (p) => p.status === "confirmed" && p.paymentDate && new Date(p.paymentDate) >= lastMonthStart && new Date(p.paymentDate) <= lastMonthEnd
      );
      const collectedThisWeek = thisWeekPayments.reduce(
        (sum2, p) => sum2 + Number(p.amount || 0),
        0
      );
      const collectedThisMonth = thisMonthPayments.reduce(
        (sum2, p) => sum2 + Number(p.amount || 0),
        0
      );
      const collectedLastMonth = lastMonthPayments.reduce(
        (sum2, p) => sum2 + Number(p.amount || 0),
        0
      );
      const pendingPayments = allPayments.filter(
        (p) => p.status === "pending"
      );
      const pendingAmount = pendingPayments.reduce(
        (sum2, p) => sum2 + Number(p.amount || 0),
        0
      );
      const activeSubscriptions = await storage.getActivePlayerSubscriptions(academyId);
      let estimatedMonthlyRevenue = 0;
      const subscriptionBreakdown = {};
      for (const sub of activeSubscriptions) {
        const price = Number(sub.price || 0);
        const monthlyEquivalent = sub.billingPeriod === "weekly" ? price * 4 : price;
        estimatedMonthlyRevenue += monthlyEquivalent;
        if (!subscriptionBreakdown[sub.planName]) {
          subscriptionBreakdown[sub.planName] = { count: 0, total: 0 };
        }
        subscriptionBreakdown[sub.planName].count++;
        subscriptionBreakdown[sub.planName].total += monthlyEquivalent;
      }
      const cashTotal = thisMonthPayments.filter((p) => p.paymentMethod === "cash").reduce((sum2, p) => sum2 + Number(p.amount || 0), 0);
      const bankTotal = thisMonthPayments.filter((p) => p.paymentMethod === "bank_transfer").reduce((sum2, p) => sum2 + Number(p.amount || 0), 0);
      const monthChange = collectedLastMonth > 0 ? Math.round(
        (collectedThisMonth - collectedLastMonth) / collectedLastMonth * 100
      ) : 0;
      const recentPayments = allPayments.slice(0, 10);
      const paymentsWithPlayers = await Promise.all(
        recentPayments.map(async (payment) => {
          const player2 = payment.playerId ? await storage.getPlayerById(payment.playerId) : null;
          return {
            id: payment.id,
            playerName: payment.payerName || player2?.name || "Unknown",
            package: "Manual Payment",
            amount: Number(payment.amount || 0),
            status: payment.status === "confirmed" ? "paid" : payment.status || "pending",
            paymentMethod: payment.paymentMethod,
            date: payment.paymentDate
          };
        })
      );
      const settings = await storage.getAcademySettings(academyId);
      const currency = settings?.currency || "AED";
      res.json({
        currency,
        // Section 1: Collected Revenue (confirmed payments only)
        collected: {
          thisWeek: collectedThisWeek,
          thisMonth: collectedThisMonth,
          lastMonth: collectedLastMonth,
          monthChange,
          cashTotal,
          bankTotal,
          tooltip: "Confirmed payments only. This is money you have actually received."
        },
        // Section 2: Pending Revenue (expected but not confirmed)
        pending: {
          amount: pendingAmount,
          count: pendingPayments.length,
          tooltip: "Pending payments awaiting confirmation. These have been recorded but not yet verified."
        },
        // Section 3: Estimated Revenue (forecast from subscriptions)
        estimated: {
          monthlyForecast: estimatedMonthlyRevenue,
          activeSubscriptions: activeSubscriptions.length,
          breakdown: Object.entries(subscriptionBreakdown).map(
            ([planName, data]) => ({
              planName,
              count: data.count,
              monthlyTotal: data.total
            })
          ),
          tooltip: "Estimated revenue based on active player subscriptions. This is a forecast, not actual collected money."
        },
        // Recent payment activity
        recentPayments: paymentsWithPlayers,
        // Legacy format for backward compatibility
        revenue: {
          thisWeek: collectedThisWeek,
          thisMonth: collectedThisMonth,
          weekChange: 0,
          monthChange,
          weekSessions: 0,
          monthSessions: 0
        },
        summary: {
          collected: collectedThisMonth,
          pending: pendingAmount,
          overdue: 0
          // We don't track overdue status in manual payments
        },
        payments: paymentsWithPlayers,
        subscriptions: {
          total: activeSubscriptions.length,
          monthlyRevenue: estimatedMonthlyRevenue,
          breakdown: Object.entries(subscriptionBreakdown).map(
            ([type, data]) => ({
              type,
              count: data.count
            })
          )
        }
      });
    } catch (error) {
      console.error("Owner finance error:", error);
      res.status(500).json({ error: "Failed to fetch finance data" });
    }
  }
);
